changeSet.sql:
DROP VIEW IF EXISTS nexus.diag_chash_conformance;
DROP VIEW IF EXISTS nexus.collection_vector_stats;
DROP VIEW IF EXISTS nexus.live_chunks;

ALTER TABLE nexus.chunks_384  DROP CONSTRAINT IF EXISTS chunks_384_chash_len_check;
ALTER TABLE nexus.chunks_768  DROP CONSTRAINT IF EXISTS chunks_768_chash_len_check;
ALTER TABLE nexus.chunks_1024 DROP CONSTRAINT IF EXISTS chunks_1024_chash_len_check;
ALTER TABLE nexus.catalog_document_chunks DROP CONSTRAINT IF EXISTS catalog_document_chunks_chash_len_check;
ALTER TABLE nexus.chash_index DROP CONSTRAINT IF EXISTS chash_index_chash_len_check;

ALTER TABLE nexus.chunks_384
    ADD CONSTRAINT chunks_384_chash_octet_check CHECK (octet_length(chash) = 32) NOT VALID;
ALTER TABLE nexus.chunks_768
    ADD CONSTRAINT chunks_768_chash_octet_check CHECK (octet_length(chash) = 32) NOT VALID;
ALTER TABLE nexus.chunks_1024
    ADD CONSTRAINT chunks_1024_chash_octet_check CHECK (octet_length(chash) = 32) NOT VALID;
ALTER TABLE nexus.catalog_document_chunks
    ADD CONSTRAINT catalog_document_chunks_chash_octet_check CHECK (octet_length(chash) = 32) NOT VALID;
ALTER TABLE nexus.chash_index
    ADD CONSTRAINT chash_index_chash_octet_check CHECK (octet_length(chash) = 32) NOT VALID;

changeSet.rollback:
ALTER TABLE nexus.chash_index DROP CONSTRAINT IF EXISTS chash_index_chash_octet_check;
ALTER TABLE nexus.catalog_document_chunks DROP CONSTRAINT IF EXISTS catalog_document_chunks_chash_octet_check;
ALTER TABLE nexus.chunks_1024 DROP CONSTRAINT IF EXISTS chunks_1024_chash_octet_check;
ALTER TABLE nexus.chunks_768  DROP CONSTRAINT IF EXISTS chunks_768_chash_octet_check;
ALTER TABLE nexus.chunks_384  DROP CONSTRAINT IF EXISTS chunks_384_chash_octet_check;

changeSet.sql:
CREATE TABLE nexus.chash_alias (
    tenant_id  TEXT  NOT NULL DEFAULT '',
    old_ref    TEXT  NOT NULL,
    old_bytes  BYTEA NOT NULL,
    new_chash  BYTEA NOT NULL,
    source     TEXT  NOT NULL DEFAULT '',
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    CONSTRAINT chash_alias_pk PRIMARY KEY (tenant_id, old_ref),
    CONSTRAINT chash_alias_new_octet_check CHECK (octet_length(new_chash) = 32)
);
CREATE INDEX idx_chash_alias_old_bytes ON nexus.chash_alias (tenant_id, old_bytes);
CREATE INDEX idx_chash_alias_new ON nexus.chash_alias (tenant_id, new_chash);
ALTER TABLE nexus.chash_alias ENABLE ROW LEVEL SECURITY;
ALTER TABLE nexus.chash_alias FORCE ROW LEVEL SECURITY;
CREATE POLICY tenant_isolation ON nexus.chash_alias
    USING (tenant_id = current_setting('nexus.tenant', true))
    WITH CHECK (tenant_id = current_setting('nexus.tenant', true));

ALTER TABLE nexus.chash_remap DROP CONSTRAINT IF EXISTS chash_remap_new_chash_len_32;
ALTER TABLE nexus.chash_remap
    ADD CONSTRAINT chash_remap_new_chash_len CHECK (length(new_chash) IN (32, 64));

changeSet.rollback:
ALTER TABLE nexus.chash_remap DROP CONSTRAINT IF EXISTS chash_remap_new_chash_len;
ALTER TABLE nexus.chash_remap
    ADD CONSTRAINT chash_remap_new_chash_len_32 CHECK (length(new_chash) = 32);

changeSet.sql:
ANALYZE nexus.chunks_384;
ANALYZE nexus.chunks_768;
ANALYZE nexus.chunks_1024;
ANALYZE nexus.catalog_document_chunks;
ANALYZE nexus.chash_index;
